            "monthly_consumption_usd < 30% of licensed_seats * seat_cost"
          ]
        },
        "stable": {
          "conditions": [
            "renewal_date > 90 days AND avg_seat_utilization between 40-70%",
            "monthly_active_users stable (variance < 15% over 6 months)",
