          ]
        },
        "growing": {
          "conditions": [
            "avg_seat_utilization > 70%",
            "monthly_active_users increasing trend (3+ months)",
            "login_frequency or feature_adoption trending upward",
            "monthly_consumption_usd > 80% of licensed_seats * seat_cost"
          ]
        },
        "no_recent_activity": {
          "conditions": [
            "monthly_active_users = 0 for last 3+ months",
            "login_frequency = 0",
            "feature_adoption = 0"
          ]
        }
      },
