          "trigger": "classification = 'growing' AND renewal_date within 120 days",
          "action": "Proactive outreach to increase seat count; negotiate multi-year deal"
        },
        "hold": {
          "trigger": "classification = 'stable'",
          "action": "Standard renewal process; monitor utilization quarterly"
        },
        "reduce": {
          "trigger": "classification = 'at_risk' AND avg_seat_utilization < 30%",
          "action": "Recommend license downsize; risk mitigation conversation pre-renewal"
        },
        "no_action": {
          "trigger": "classification = 'no_recent_activity'",
          "action": "Investigate account health; consider churn risk; engagement strategy required"
        }
